import React from "react";
import { Link, useLocation } from "react-router-dom";
import { Bus } from "../types";

type Booking = {
  id: string;
  selectedSeats: number[];
  passengerDetails: Array<{
    seatNumber: number;
    name: string;
    age: number;
    gender: string;
  }>;
  totalPrice: number;
};

type ConfirmationState = {
  booking?: Booking;
  bus?: Bus;
  successMessage?: string;
};

const Confirmation: React.FC = () => {
  const location = useLocation();
  const state = (location.state || {}) as ConfirmationState;

  if (!state.booking || !state.bus) {
    return (
      <section className="rounded-2xl bg-white p-8 text-center shadow-travel ring-1 ring-slate-200">
        <h2 className="text-2xl font-bold text-slate-900">No booking found</h2>
        <Link to="/" className="mt-4 inline-block rounded-lg bg-blue-600 px-4 py-2 text-white">
          Back to Home
        </Link>
      </section>
    );
  }

  return (
    <section className="mx-auto max-w-2xl rounded-2xl bg-white p-8 shadow-travel ring-1 ring-slate-200">
      <p className="text-sm font-semibold uppercase tracking-wide text-emerald-600">
        {state.successMessage || "Booking Successful 🎉"}
      </p>
      <h2 className="mt-2 text-3xl font-bold text-slate-900">Your seats are confirmed</h2>

      <div className="mt-6 space-y-2 text-slate-700">
        <p>
          <span className="font-semibold">Bus:</span> {state.bus.operatorName}
        </p>
        <p>
          <span className="font-semibold">Route:</span> {state.bus.departureCity} {" -> "} {state.bus.arrivalCity}
        </p>
        <p>
          <span className="font-semibold">Seat numbers:</span> {state.booking.selectedSeats.join(", ")}
        </p>
        <p>
          <span className="font-semibold">Passenger Names:</span>{" "}
          {state.booking.passengerDetails?.map((p) => p.name).join(", ") || "N/A"}
        </p>
        <p>
          <span className="font-semibold">Total price:</span> INR {state.booking.totalPrice}
        </p>
      </div>

      <Link
        to="/"
        className="mt-6 inline-block rounded-lg bg-blue-600 px-4 py-2.5 font-semibold text-white transition hover:bg-blue-700"
      >
        Back to Home
      </Link>
    </section>
  );
};

export default Confirmation;
